/****
 * Get the highest value among CQP_MLI_USD, CQP_MLE_USD, and CQP_MLD_USD
 * Handles null, undefined, and string values safely
 * By Adriana Centellas
 ****/

function safeNumber(v) {
  if (typeof v !== "string" && typeof v !== "number") return 0;

  const normalized = String(v).replace(/,/g, "");
  const n = Number(normalized);

  return Number.isNaN(n) ? 0 : n;
}

function getHighestUSD() {
  // Convert to numbers and replace null/undefined with 0
  const mli = parseFloat(safeNumber(this.CQP_MLI_USD)) || 0;
  const mle = parseFloat(safeNumber(this.CQP_MLE_USD)) || 0;
  const mld = parseFloat(safeNumber(this.CQP_MLD_USD)) || 0;

  // Return the largest
  return Math.max(mli, mle, mld);
}


const highestValue = getHighestUSD();
return highestValue;
